mapping:
(
  $cell := function($value) { $exists($value) and $type($value) != "null" ? $value : "" };
  $year := function($date) {(
    $dateText := $exists($date) and $type($date) != "null" ? $replace($string($date), /^"|"$/, "") : "";
    $match($dateText, /^\d{4}/) ? $number($substring($dateText, 0, 4)) : ""
  )};
  $firstDate := function($primary, $fallback) {
    $exists($primary) and $type($primary) != "null" and $string($primary) != "" ? $primary : $fallback
  };
  $num := function($value) {(
    $exists($value) and $type($value) != "null" ? (
      $type($value) = "number" ? $value : (
        $text := $replace($string($value), ",", ".");
        $match($text, /^-?\d+(\.\d+)?$/) ? $number($text) : 0
      )
    ) : 0
  )};
  $gebuehrenart := function($label) {(
    $lower := $exists($label) and $type($label) != "null" ? $lowercase($string($label)) : "";
    $contains($lower, "gold") ? "gold-oa" : ($contains($lower, "hybrid") ? "hybrid-oa" : "")
  )};
  $row := function($bemerkung, $originalwaehrung, $originalbetrag, $euroNetto, $steuersatz, $euroBrutto, $gebuehrenartValue, $mitgliedschaft, $rechnungsjahr) {
    {
      "DOI": $cell(doi),
      "förderfähig": "",
      "Bemerkung": $cell($bemerkung),
      "Name des Verlags": $cell(publisher.label),
      "Publikationsform": $cell(pub_type.label),
      "CC-Lizenz": $cell(best_oa_license),
      "Originalwährung": $cell($originalwaehrung),
      "Rechnungsbetrag in Originalwährung": $cell($originalbetrag),
      "Euro netto": $cell($euroNetto),
      "Steuersatz": $cell($steuersatz),
      "Euro brutto": $cell($euroBrutto),
      "Kostensplittung": "",
      "Zuschussbetrag DFG": "",
      "Gebührenart": $cell($gebuehrenartValue),
      "Zuordnung zu Mitgliedschaft": $cell($mitgliedschaft),
      "Zuordnung zu Transformationsvertrag": $cell(contract.label),
      "Rechnungsjahr / Lizenzjahr": $cell($rechnungsjahr),
      "Publikationsjahr": $year($firstDate(pub_date, pub_date_print)),
      "Projektnummer/Projekt ID DFG": $cell(grant_number),
      "DFG-Wissenschaftsbereich": ""
    }
  };
  $costItemRow := function($invoice, $item) {(
    $net := $num($item.euro_value);
    $vat := $num($item.vat);
    $vatRate := $net != 0 ? $vat / $net : "";
    $row($item.label, $item.orig_currency, $item.orig_value, $item.euro_value, $vatRate, $net + $vat, $item.cost_type.label, "", $year($invoice.date))
  )};
  $hasInvoices := $type(invoices) = "array" and $count(invoices) > 0;
  $invoiceRows := $reduce(invoices[$count(cost_items) > 0], function($rows, $invoice) {
    $append($rows, $map($invoice.cost_items, function($item) { $costItemRow($invoice, $item) }))
  }, []);
  $hasInvoices ? ($exists($invoiceRows) ? $invoiceRows : []) : (contract ? [$row("", "", "", 0, 0, 0, $gebuehrenart(oa_category.label), "", contract_year)] : [])
)
